import{_ as d,c,o as h,a1 as p}from"./chunks/framework.DDNAyvCW.js";const u="/assets/quick_start.DQjiNycC.png";(function(){const n={win:"https://static-download.chaterm.net/chaterm-latest-setup-x64.exe",mac_arm:"https://static-download.chaterm.net/chaterm-latest-macos-arm64.dmg",mac_x64:"https://static-download.chaterm.net/chaterm-latest-macos-x64.dmg",linux_deb:"https://static-download.chaterm.net/chaterm-latest-linux-amd64.deb"};function i(){if(typeof window>"u")return null;const t=navigator.userAgentData,e=(navigator.userAgent||"").toLowerCase(),s=(navigator.platform||"").toLowerCase();if(t!=null&&t.platform){const a=t.platform.toLowerCase();if(a.includes("android"))return"Android";if(a.includes("ios"))return"iOS"}if(/android/i.test(e))return"Android";const o=s==="macintel"&&typeof navigator.maxTouchPoints=="number"&&navigator.maxTouchPoints>1;return/iphone|ipod|ipad/i.test(e)||o?"iOS":/windows|win32|win64|wow64/i.test(e)?"Windows":!o&&(/mac|macintosh|darwin/i.test(e)||s.includes("mac"))?"macOS":/linux|x11/i.test(e)&&!/android/i.test(e)?"Linux":null}async function l(){var e;if(typeof window>"u")return"arm64";if((e=navigator.userAgentData)!=null&&e.getHighEntropyValues)try{const{architecture:s}=await navigator.userAgentData.getHighEntropyValues(["architecture"]);if(s==="arm")return"arm64";if(s)return"x64"}catch{}const t=navigator.userAgent.toLowerCase();return t.includes("arm")||t.includes("aarch64")?"arm64":t.includes("x86_64")||t.includes("amd64")||t.includes("intel")?"x64":"arm64"}async function r(){if(typeof window>"u")return;const t=i(),e=document.getElementById("smart-download-btn"),s=document.getElementById("download-btn-text");if(!t){e&&(e.style.display="none");return}let o=t,a=null;t==="Windows"?(o="Windows",a=n.win):t==="macOS"?await l()==="x64"?(o="macOS (Intel)",a=n.mac_x64):(o="macOS (Apple Silicon)",a=n.mac_arm):t==="Linux"?(o="Linux",a=n.linux_deb):(o=t,a="/download/"),e&&a&&(e.href=a,e.target="_blank",e.style.display="inline-flex"),s&&(s.textContent="Download "+o+" version")}typeof window<"u"&&typeof document<"u"&&(document.readyState==="loading"?document.addEventListener("DOMContentLoaded",function(){setTimeout(r,100)}):setTimeout(r,100))})();const b=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"docs/start/quickstart/index.md","filePath":"docs/start/quickstart/index.md"}'),m={name:"docs/start/quickstart/index.md"};function g(n,i,l,r,t,e){return h(),c("div",null,i[0]||(i[0]=[p('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">What you&#39;ll learn</p><ul><li>How to install Chaterm and sign in to your account</li><li>How to add and connect to a remote host via SSH</li><li>How to use AI-powered Command, and Agent modes</li><li>How to run real-world tasks like system monitoring and log analysis</li></ul></div><h2 id="step-1-install-and-sign-in" tabindex="-1">Step 1: Install and Sign In <a class="header-anchor" href="#step-1-install-and-sign-in" aria-label="Permalink to &quot;Step 1: Install and Sign In&quot;">​</a></h2><h3 id="install-chaterm" tabindex="-1">Install Chaterm <a class="header-anchor" href="#install-chaterm" aria-label="Permalink to &quot;Install Chaterm&quot;">​</a></h3><p>Download the installer for your operating system. The button below auto-detects your platform.</p><div id="smart-download-section" class="smart-download-container"><a id="smart-download-btn" href="/download/" class="smart-download-btn" style="display:none;"><span class="download-icon">⤓</span><span id="download-btn-text">Download Chaterm</span></a></div><p>Don&#39;t see your platform? Visit the <a href="/docs/start/downloads/">Downloads</a> page for all available packages.</p><p>Open the downloaded installer and follow the on-screen prompts to complete installation. Launch Chaterm once it is ready.</p><h3 id="sign-in" tabindex="-1">Sign In <a class="header-anchor" href="#sign-in" aria-label="Permalink to &quot;Sign In&quot;">​</a></h3><p>Select one of the following sign-in methods:</p><ul><li><strong>Email verification code</strong> -- Enter your email address, then enter the one-time code sent to your inbox.</li><li><strong>Username and password</strong> -- Enter your existing account credentials.</li><li><strong>Third-party login</strong> -- Click the Google, GitHub, or Apple ID button to authenticate.</li></ul><div class="tip custom-block"><p class="custom-block-title">First-time users</p><p>When you sign in with an email for the first time, Chaterm automatically creates a new account for you. No separate registration step is needed.</p></div><div class="warning custom-block"><p class="custom-block-title">Skipping sign-in</p><p>You can click <strong>Skip</strong> to use Chaterm without an account, but the uilt-in AI model requires you to log in before you can use it.</p></div><h2 id="step-2-add-a-host" tabindex="-1">Step 2: Add a Host <a class="header-anchor" href="#step-2-add-a-host" aria-label="Permalink to &quot;Step 2: Add a Host&quot;">​</a></h2><p>Open the host management panel and add your first remote server. Below is a summary of the key fields.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Label</strong></td><td>A friendly name for this host</td><td><code>my-web-server</code></td></tr><tr><td><strong>Host</strong></td><td>IP address or hostname</td><td><code>192.168.1.100</code></td></tr><tr><td><strong>Port</strong></td><td>SSH port number</td><td><code>22</code></td></tr><tr><td><strong>Username</strong></td><td>SSH login user</td><td><code>root</code></td></tr><tr><td><strong>Auth Method</strong></td><td>Password or private key</td><td>Password</td></tr></tbody></table><p>For a full walkthrough with screenshots, see <a href="/docs/hosts/add-personal">Add a Personal Host</a>.</p><h3 id="connect-to-a-host" tabindex="-1">Connect to a Host <a class="header-anchor" href="#connect-to-a-host" aria-label="Permalink to &quot;Connect to a Host&quot;">​</a></h3><p>Click any host in the host list to establish an SSH connection. A new terminal tab opens automatically once the connection succeeds.</p><h2 id="step-3-try-ai-features" tabindex="-1">Step 3: Try AI Features <a class="header-anchor" href="#step-3-try-ai-features" aria-label="Permalink to &quot;Step 3: Try AI Features&quot;">​</a></h2><p><img src="'+u+'" alt=""></p><h3 id="open-the-ai-conversation-panel" tabindex="-1">Open the AI Conversation Panel <a class="header-anchor" href="#open-the-ai-conversation-panel" aria-label="Permalink to &quot;Open the AI Conversation Panel&quot;">​</a></h3><p>Use either of these methods:</p><ol><li><strong>Click the AI icon</strong> in the left sidebar.</li><li><strong>Press a keyboard shortcut</strong> in the terminal: <ul><li>macOS: <code>Cmd + L</code></li><li>Windows/Linux: <code>Ctrl + L</code></li></ul></li></ol><h3 id="choose-an-interaction-mode" tabindex="-1">Choose an Interaction Mode <a class="header-anchor" href="#choose-an-interaction-mode" aria-label="Permalink to &quot;Choose an Interaction Mode&quot;">​</a></h3><p>Click <strong>New Conversation</strong>, then select the mode that fits your task:</p><table tabindex="0"><thead><tr><th>Mode</th><th>When to use</th><th>Runs commands?</th></tr></thead><tbody><tr><td><strong>Command</strong></td><td>Execute commands in the active terminal</td><td>Yes (current terminal)</td></tr><tr><td><strong>Agent</strong></td><td>Operate across one or more hosts</td><td>Yes (any host via <code>@</code>)</td></tr></tbody></table><p>Select a model from the model dropdown, then type your prompt and press Enter.</p><h3 id="use-in-terminal-ai-shortcuts" tabindex="-1">Use In-Terminal AI Shortcuts <a class="header-anchor" href="#use-in-terminal-ai-shortcuts" aria-label="Permalink to &quot;Use In-Terminal AI Shortcuts&quot;">​</a></h3><p>While working inside a terminal session, you have two fast paths to AI:</p><ul><li><strong><code>Ctrl+K</code> / <code>Cmd+K</code></strong> -- Opens an inline prompt dialog. Type what you need and the AI generates a command.</li><li><strong><code>Ctrl+L</code> / <code>Cmd+L</code></strong> -- Opens the AI conversation panel with your current terminal context already attached.</li></ul><div class="tip custom-block"><p class="custom-block-title">Example with Ctrl+K</p><p>Press <code>Cmd+K</code>, type <code>show disk usage sorted by size</code>, and the AI returns:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">du</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre></div><p>Press Enter to execute it directly in your terminal.</p></div><h2 id="try-it-now" tabindex="-1">Try It Now <a class="header-anchor" href="#try-it-now" aria-label="Permalink to &quot;Try It Now&quot;">​</a></h2><p>Copy and paste these prompts into the AI conversation panel to see Chaterm in action.</p><h3 id="monitor-system-resources-across-hosts" tabindex="-1">Monitor system resources across hosts <a class="header-anchor" href="#monitor-system-resources-across-hosts" aria-label="Permalink to &quot;Monitor system resources across hosts&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@my-web-server Check CPU and memory usage. Flag anything above 80%.</span></span></code></pre></div><p><strong>Expected output:</strong> The AI runs <code>top</code>, <code>free -h</code>, and similar commands, then summarizes resource usage with a clear warning for any metric that exceeds 80%.</p><h3 id="analyze-recent-error-logs" tabindex="-1">Analyze recent error logs <a class="header-anchor" href="#analyze-recent-error-logs" aria-label="Permalink to &quot;Analyze recent error logs&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@my-web-server Find ERROR lines in /var/log/syslog from the last 2 hours and group them by source.</span></span></code></pre></div><p><strong>Expected output:</strong> The AI runs <code>journalctl</code> or <code>grep</code> with appropriate time filters, then presents a grouped summary of errors with counts and timestamps.</p><h3 id="clean-up-old-temporary-files" tabindex="-1">Clean up old temporary files <a class="header-anchor" href="#clean-up-old-temporary-files" aria-label="Permalink to &quot;Clean up old temporary files&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@my-web-server List all files in /tmp older than 7 days, show their total size, then delete them after confirmation.</span></span></code></pre></div><p><strong>Expected output:</strong> The AI first runs <code>find /tmp -mtime +7</code> to list matching files, shows you the list and total disk usage, then asks for your confirmation before executing the removal.</p><div class="warning custom-block"><p class="custom-block-title">Always review before executing</p><p>In Command and Agent modes the AI can run real commands on your servers. Review each proposed command before confirming execution, especially for destructive operations like <code>rm</code>, <code>drop</code>, or <code>truncate</code>.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you have Chaterm up and running, explore these areas to go deeper:</p><ul><li><strong><a href="/docs/ai/dialogs/">AI Conversations</a></strong> -- Learn about conversation history, context management, and multi-turn workflows.</li><li><strong><a href="/docs/ai/llms/">AI Model Settings</a></strong> -- Configure which models to use and bring your own API keys.</li><li><strong><a href="/docs/hosts/">Host Management</a></strong> -- Organize hosts, set up bastion/jump servers, and import/export configurations.</li><li><strong><a href="/docs/terminal/operations/">Terminal Operations</a></strong> -- Master split panes, tabs, snippets, and other terminal features.</li><li><strong><a href="/docs/mcp/usage/">MCP Integration</a></strong> -- Extend Chaterm with Model Context Protocol tools and servers.</li><li><strong><a href="/docs/settings/shortcuts/">Keyboard Shortcuts</a></strong> -- Customize keybindings for faster navigation.</li><li><strong><a href="/docs/settings/billing/">Billing and Plans</a></strong> -- Understand usage limits, upgrade options, and team plans.</li></ul>',47)]))}const k=d(m,[["render",g]]);export{b as __pageData,k as default};
